<template>
  <div class="page-bg"><section class="page-banner"><div class="container"><span class="eyebrow">找到你的家人</span><h1>等待领养的萌宠</h1><p>认真了解它的过去，也认真考虑你们的未来。</p></div></section><div class="container listing-wrap"><aside class="filter-panel"><div class="filter-title"><h3>筛选条件</h3><el-button type="text" @click="reset">重置</el-button></div><label>关键词</label><el-input v-model.trim="query.keyword" clearable prefix-icon="el-icon-search" placeholder="宠物名称或品种" @keyup.enter.native="search" /><label>宠物大类</label><el-select v-model="query.categoryId" clearable placeholder="全部大类" @change="categoryChanged"><el-option v-for="item in categories" :key="item.id" :label="item.name" :value="item.id" /></el-select><label>细分品种</label><el-select v-model="query.subcategoryId" clearable placeholder="全部品种"><el-option v-for="item in subcategories" :key="item.id" :label="item.name" :value="item.id" /></el-select><label>领养状态</label><el-select v-model="query.status" clearable placeholder="全部状态"><el-option label="待领养" value="AVAILABLE" /><el-option label="领养中" value="IN_PROGRESS" /><el-option label="已领养" value="ADOPTED" /></el-select><el-button class="filter-submit" type="primary" icon="el-icon-search" @click="search">查找萌宠</el-button></aside><section class="listing-main"><div class="result-bar"><div><strong>{{ total }}</strong> 位平台萌宠符合当前条件</div><el-radio-group v-model="query.status" size="small" @change="search"><el-radio-button label="">全部</el-radio-button><el-radio-button label="AVAILABLE">待领养</el-radio-button><el-radio-button label="IN_PROGRESS">领养中</el-radio-button></el-radio-group></div><div v-loading="loading" class="pet-grid listing-grid"><PetCard v-for="pet in pets" :key="pet.id" :pet="pet" /></div><el-empty v-if="!loading && !pets.length" description="没有找到符合条件的萌宠，换个条件试试吧" /><el-pagination v-if="total>query.pageSize" background layout="prev, pager, next, jumper" :total="total" :page-size="query.pageSize" :current-page.sync="query.page" @current-change="load" /></section></div></div>
</template>
<script>
import { categoryApi, petApi } from '../api'; import PetCard from '../components/PetCard.vue'
export default { components:{PetCard}, data:()=>({categories:[],pets:[],total:0,loading:false,query:{keyword:'',categoryId:null,subcategoryId:null,status:'AVAILABLE',page:1,pageSize:12}}), computed:{subcategories(){const c=this.categories.find(x=>x.id===this.query.categoryId);return c?c.children:[]}}, async created(){this.query.categoryId=this.$route.query.categoryId?Number(this.$route.query.categoryId):null;const routeStatus=this.$route.query.status;if(['AVAILABLE','IN_PROGRESS','ADOPTED',''].includes(routeStatus))this.query.status=routeStatus;this.categories=await categoryApi.tree();this.load()}, methods:{categoryChanged(){this.query.subcategoryId=null},search(){this.query.page=1;this.load()},reset(){this.query={keyword:'',categoryId:null,subcategoryId:null,status:'AVAILABLE',page:1,pageSize:12};this.load()},async load(){this.loading=true;try{const data=await petApi.list(this.query);this.pets=data.records;this.total=data.total}finally{this.loading=false}}} }
</script>
